import{_ as e,o as i,c as o,a2 as t}from"./chunks/framework.DGp-bpT-.js";const p=JSON.parse('{"title":"Настройка интеграции с Discord","description":"","frontmatter":{},"headers":[],"relativePath":"guide/discord-setup.md","filePath":"guide/discord-setup.md","lastUpdated":1776065155000}'),a={name:"guide/discord-setup.md"};function l(r,s,n,d,c,g){return i(),o("div",null,[...s[0]||(s[0]=[t(`<h1 id="настроика-интеграции-с-discord" tabindex="-1">Настройка интеграции с Discord <a class="header-anchor" href="#настроика-интеграции-с-discord" aria-label="Permalink to &quot;Настройка интеграции с Discord&quot;">​</a></h1><p>Интеграция SREBot с Discord позволяет боту анализировать сообщения в каналах, искать в них алерты от Alertmanager и проводить их автоматический анализ с помощью ИИ.</p><hr><h2 id="_1-регистрация-приложения-в-discord" tabindex="-1">1. Регистрация приложения в Discord <a class="header-anchor" href="#_1-регистрация-приложения-в-discord" aria-label="Permalink to &quot;1. Регистрация приложения в Discord&quot;">​</a></h2><ol><li>Перейдите на <a href="https://discord.com/developers/applications" target="_blank" rel="noreferrer">Discord Developer Portal</a>.</li><li>Нажмите кнопку <strong>New Application</strong>.</li><li>Введите название (например, <code>SREBot</code>) и подтвердите создание.</li></ol><h2 id="_2-создание-бота-и-получение-токена" tabindex="-1">2. Создание бота и получение токена <a class="header-anchor" href="#_2-создание-бота-и-получение-токена" aria-label="Permalink to &quot;2. Создание бота и получение токена&quot;">​</a></h2><ol><li>В боковом меню выберите раздел <strong>Bot</strong>.</li><li>Нажмите <strong>Reset Token</strong> (или <strong>Copy Token</strong>, если он уже виден), чтобы получить токен. <ul><li><strong>Сохраните этот токен!</strong> В конфиге бота это <code>DISCORD_BOT_TOKEN</code>.</li></ul></li><li>В этом же разделе прокрутите вниз до <strong>Privileged Gateway Intents</strong>.</li><li><strong>ОБЯЗАТЕЛЬНО</strong> включите переключатель <strong>Message Content Intent</strong>. Без этого бот не сможет читать тексты алертов.</li><li>Нажмите <strong>Save Changes</strong>.</li></ol><h2 id="_3-приглашение-бота-на-сервер" tabindex="-1">3. Приглашение бота на сервер <a class="header-anchor" href="#_3-приглашение-бота-на-сервер" aria-label="Permalink to &quot;3. Приглашение бота на сервер&quot;">​</a></h2><ol><li>Перейдите в раздел <strong>OAuth2 -&gt; URL Generator</strong>.</li><li>В списке <strong>Scopes</strong> выберите <code>bot</code>.</li><li>В появившемся списке <strong>Bot Permissions</strong> выберите следующие права: <ul><li><code>Read Messages / View Channels</code></li><li><code>Send Messages</code></li><li><code>Embed Links</code> (рекомендуется)</li><li><code>Read Message History</code></li></ul></li><li>Скопируйте сгенерированную ссылку внизу страницы и откройте её в браузере.</li><li>Выберите свой сервер и подтвердите добавление бота.</li></ol><h2 id="_4-получение-id-канала" tabindex="-1">4. Получение ID канала <a class="header-anchor" href="#_4-получение-id-канала" aria-label="Permalink to &quot;4. Получение ID канала&quot;">​</a></h2><ol><li>В Discord перейдите в <strong>User Settings -&gt; Advanced</strong>.</li><li>Включите <strong>Developer Mode</strong>.</li><li>Щелкните правой кнопкой мыши по каналу, в котором бот должен слушать алерты, и выберите <strong>Copy Channel ID</strong>. <ul><li>Это числовое значение будет <code>DISCORD_CHANNEL_ID</code> в конфиге бота.</li></ul></li></ol><h2 id="_5-настроика-бота-env" tabindex="-1">5. Настройка бота (Env) <a class="header-anchor" href="#_5-настроика-бота-env" aria-label="Permalink to &quot;5. Настройка бота (Env)&quot;">​</a></h2><p>Добавьте полученные данные в ваш файл <code>.env</code> или настройки Helm:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Токен бота из Discord Developer Portal</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DISCORD_BOT_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">MTAx...your.token...</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ID канала (Snowflake ID)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DISCORD_CHANNEL_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">123456789012345678</span></span></code></pre></div><hr><h2 id="как-это-работает" tabindex="-1">Как это работает <a class="header-anchor" href="#как-это-работает" aria-label="Permalink to &quot;Как это работает&quot;">​</a></h2><ul><li><strong>Автоматический анализ</strong>: Если бот добавлен в канал и имеет права на чтение сообщений, он автоматически подхватывает любые сообщения, похожие на алерты Alertmanager, и начинает их анализ.</li><li><strong>Поддержка тредов</strong>: Если вы используете форумы или ветки (Threads) в Discord, бот будет отвечать именно в той ветке, где был опубликован алерт.</li><li><strong>Индикация процесса</strong>: При получении алерта бот сначала отправляет сообщение <code>🔍 Analyzing...</code>, а затем редактирует его, заменяя на полноценный RCA-отчёт.</li><li><strong>Обновление статуса</strong>: Если алерт переходит в статус <code>Resolved</code>, бот пришлет подтверждение ответом на оригинальное сообщение.</li></ul><hr><h2 id="резюме-необходимые-права-бота" tabindex="-1">Резюме: необходимые права бота <a class="header-anchor" href="#резюме-необходимые-права-бота" aria-label="Permalink to &quot;Резюме: необходимые права бота&quot;">​</a></h2><p>Для корректной работы SREBot в Discord должны быть включены следующие опции:</p><p><strong>Developer Portal (Bot раздел):</strong></p><ul><li>✅ <strong>Message Content Intent</strong> (раздел Privileged Gateway Intents)</li></ul><p><strong>Developer Portal (URL Generator):</strong></p><ul><li>✅ <strong>View Channels</strong> (General Permissions)</li><li>✅ <strong>Send Messages</strong> (Text Permissions)</li><li>✅ <strong>Read Message History</strong> (Text Permissions)</li></ul><p><strong>Настройки Discord сервера (для приватных каналов):</strong> Если канал приватный, добавьте бота в исключения и разрешите:</p><ul><li>✅ <strong>View Channel</strong></li><li>✅ <strong>Send Messages</strong></li><li>✅ <strong>Read Message History</strong></li></ul><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Убедитесь, что у бота есть роль с правом просмотра истории сообщений (<code>Read Message History</code>), иначе он не сможет корректно связывать Resolved-уведомления с исходными алертами.</p></div>`,27)])])}const u=e(a,[["render",l]]);export{p as __pageData,u as default};
